 88→func TestHMACValidator_RSASignedToken(t *testing.T) {
 89→	// An HS256 validator should reject tokens signed with a different method.
 90→	// We simulate this by creating a token that claims RS256 but is actually nonsense.
 91→	token := jwt.NewWithClaims(jwt.SigningMethodHS256, &Claims{
 92→		RegisteredClaims: jwt.RegisteredClaims{
 93→			ExpiresAt: jwt.NewNumericDate(time.Now().Add(time.Hour)),
 94→		},
 95→	})
 96→	// Override the header to claim RS256
 97→	token.Header["alg"] = "RS256"
 98→	// Sign with HMAC secret (the header lies about the algorithm)
 99→	signed, err := token.SignedString([]byte(testSecret))
100→	if err != nil {
101→		t.Fatalf("failed to sign token: %v", err)
102→	}
103→
104→	v := NewHMACValidator(testSecret)
105→	_, err = v.Validate(signed)
106→	if err == nil {
107→		t.Fatal("expected error for RS256-header token validated by HMAC validator")
108→	}
109→}
