111→func TestWithAndGetClaims(t *testing.T) {
112→	claims := &Claims{Email: "user@example.com"}
113→	ctx := WithClaims(context.Background(), claims)
114→
115→	got := GetClaims(ctx)
116→	if got == nil {
117→		t.Fatal("GetClaims returned nil")
118→	}
119→	if got.Email != "user@example.com" {
120→		t.Errorf("Email = %q, want %q", got.Email, "user@example.com")
121→	}
